  function parseRecallIntent(value) {
    const text = normalizeSearchText(value);
    const floors = [];
    const floorPattern = /(?:第\s*)?(\d{1,6})\s*(?:楼|层|条|轮)/g;
    let match;
    while ((match = floorPattern.exec(text))) floors.push(Number(match[1]));
    const detailed = /(具体说了什么|原话|还原|详细回忆|当时.*说|第\s*\d+\s*(楼|层|条|轮))/.test(text);
    const timeHints = [];
    if (/(刚才|上一轮|上次)/.test(text)) timeHints.push('recent');
    if (/(最初|一开始|很久以前|早先)/.test(text)) timeHints.push('early');
    return {
      floors: [...new Set(floors)],
      detailed,
      detailLevel: detailed ? 'L3' : /(回忆|记得|当时|曾经)/.test(text) ? 'L2' : 'L1',
      tokens: tokenize(text),
      entities: extractEntities(text),
      quotes: extractQuotes(text),
      timeHints,
    };
  }

  function openMemoryDb() {
    if (dbPromise) return dbPromise;
    dbPromise = new Promise((resolve, reject) => {
      if (typeof indexedDB === 'undefined') {
        reject(new Error('当前 WebView 不支持 IndexedDB'));
        return;
      }
      const request = indexedDB.open(DB_NAME, DB_VERSION);
      request.onupgradeneeded = () => {
        const db = request.result;
        STORE_NAMES.forEach((name) => {
          if (!db.objectStoreNames.contains(name)) db.createObjectStore(name, { keyPath: 'id' });
        });
      };
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error || new Error('IndexedDB 打开失败'));
    });
    return dbPromise;
  }

  async function dbGet(storeName, id) {
    const db = await openMemoryDb();
    return new Promise((resolve, reject) => {
      const request = db.transaction(storeName, 'readonly').objectStore(storeName).get(id);
      request.onsuccess = () => resolve(request.result || null);
      request.onerror = () => reject(request.error);
    });
  }

  async function dbPutMany(storeName, rows) {
    if (!rows.length) return;
    const db = await openMemoryDb();
    await new Promise((resolve, reject) => {
      const transaction = db.transaction(storeName, 'readwrite');
      const store = transaction.objectStore(storeName);
      rows.forEach((row) => store.put(row));
      transaction.oncomplete = resolve;
      transaction.onerror = () => reject(transaction.error);
      transaction.onabort = () => reject(transaction.error);
    });
  }

  async function dbDeleteWhere(storeName, predicate) {
    const db = await openMemoryDb();
    await new Promise((resolve, reject) => {
      const transaction = db.transaction(storeName, 'readwrite');
      const request = transaction.objectStore(storeName).openCursor();
      request.onsuccess = () => {
        const cursor = request.result;
        if (!cursor) return;
        if (predicate(cursor.value)) cursor.delete();
        cursor.continue();
      };
      request.onerror = () => reject(request.error);
      transaction.oncomplete = resolve;
      transaction.onerror = () => reject(transaction.error);
      transaction.onabort = () => reject(transaction.error);
    });
  }

  function dbDeleteByScopeAndMessage(storeName, scope, messageId) {
    return dbDeleteWhere(storeName, (row) => row.scope === scope && Number(row.message_id) === Number(messageId));
  }

  async function dbGetAll(storeName) {
    const db = await openMemoryDb();
    return new Promise((resolve, reject) => {
      const request = db.transaction(storeName, 'readonly').objectStore(storeName).getAll();
      request.onsuccess = () => resolve(request.result || []);
      request.onerror = () => reject(request.error);
    });
  }

  function splitMessageChunks(message) {
    const text = String(message.message || '');
    const parts = [];
    const pattern = /[^\n]+(?:\n+|$)/g;
    let match;
    let ordinal = 0;
    while ((match = pattern.exec(text))) {
      const raw = match[0].replace(/\n+$/, '');
      if (!raw.trim()) continue;
      const start = match.index;
      const end = start + raw.length;
      parts.push({ ordinal, text: raw, start, end });
      ordinal += 1;
    }
    if (!parts.length && text) parts.push({ ordinal: 0, text, start: 0, end: text.length });
    return parts;
  }

