  function showInjectionDanmaku(selectedEntries) {
    const $layer = ensureToastLayer();
    $layer.empty();
    const entries = Array.isArray(selectedEntries) ? selectedEntries : [];
    const names = entries.map((entry) => `${entry.required ? '[必选] ' : ''}${entry.worldbook} / ${entry.name}`);
    const visible = names.slice(0, 6);
    const more = Math.max(0, names.length - visible.length);
    const listHtml = names.length
      ? visible.map((name) => `<div class="wsr-toast-item">${escapeHtml(name)}</div>`).join('') + (more ? `<div class="wsr-toast-more">还有 ${more} 条…</div>` : '')
      : '<div class="wsr-toast-item">未注入世界书条目</div>';
    const $toast = $(`
      <div class="wsr-toast">
        <div class="wsr-toast-title"><span>${names.length ? '世界书已注入' : '本轮未注入'}</span><span class="wsr-toast-count">${names.length} 条</span></div>
        <div class="wsr-toast-list">${listHtml}</div>
      </div>
    `);
    $layer.append($toast);
    const holdMs = Math.min(6500, 2800 + names.length * 350);
    setTimeout(() => {
      $toast.addClass('is-out');
      setTimeout(() => $toast.remove(), 320);
    }, holdMs);
  }

  async function retrieveAndInject({ force = false, showResult = false } = {}) {
    const startedAt = performance.now();
    const config = hydrateApiFromGlobalBackup(loadConfig());
    if (!config.enabled && !force) return;
    if (running) return;
    const context = getRecentContext(config.historyMessages);
    const latestUser = currentUserMessage(context);
    if (!latestUser) return;
    if (!force && latestUser.id === lastUserMessageId) return;
    running = true;
    let shieldInfo = { shielded: 0, kept: 0 };
    try {
      await indexChatIncrementally({ config });
      let storyState = getStoryState();
      try {
        storyState = await updateStoryStateFromHistory(config, { force: false });
      } catch (error) {
        // 状态更新失败不阻断召回
      }
      const allBoundEntries = await getAllBoundEntries();
      const scopedEntries = filterCandidateEntries(config, allBoundEntries);
      let localWorldbooks = scoreWorldbookEntries(latestUser.content, scopedEntries).slice(0, Math.max(20, Number(config.maxSelectedEntries) * 4 || 48));
      let memoryCandidates = await retrieveMemoryCandidates(latestUser.content, config, latestUser.id);
      const localIntent = parseRecallIntent(latestUser.content);
      let plan = null;
      let degraded = '';
      let rerankMode = 'local';
      if (config.rerankEnabled !== false && config.rerankMode === 'api') {
        try {
          const reranked = await applyDedicatedRerank(config, latestUser.content, memoryCandidates, localWorldbooks);
          memoryCandidates = reranked.memory;
          localWorldbooks = reranked.worldbooks;
          rerankMode = reranked.mode || 'api';
        } catch (error) {
          degraded = `Rerank API 失败：${error.message || error}`;
          rerankMode = 'local_fallback';
        }
      }
      const useLlmPlan = config.rerankEnabled !== false && config.rerankMode !== 'off' && (config.rerankMode === 'llm' || config.llmRerank !== false) && config.baseUrl && config.model;
      if (useLlmPlan) {
        try {
          plan = await callJsonApi(config, buildPlanningMessages(config, context, memoryCandidates, localWorldbooks));
          rerankMode = rerankMode === 'api' ? 'api+llm' : 'llm';
        } catch (error) {
          degraded = [degraded, `LLM 规划失败：${error.message || error}`].filter(Boolean).join(' · ');
        }
      }
      const selectedMemory = plan ? selectByIds(memoryCandidates, plan.memory_ids) : memoryCandidates.slice(0, Math.max(4, Number(config.memoryTopK) || 12));
      const plannedBooks = plan ? selectByIds(localWorldbooks, plan.worldbook_ids) : localWorldbooks.slice(0, Math.max(1, Number(config.maxSelectedEntries) || 12));
      const selectedEntries = mergeSelectedWithRequired(plannedBooks, allBoundEntries, config.requiredEntryIds || []);
      const detailLevel = /^L[0-3]$/.test(plan?.detail_level) ? plan.detail_level : localIntent.detailLevel;
      const evidence = await buildEvidenceEntries(selectedMemory, detailLevel, config);
      const recapText = await buildRecapText(config, latestUser.id);
      const characterText = config.characterTrackEnabled === false
        ? ''
        : formatCharacterStates(storyState.characters || {}, config.characterBudget);
      const outline = String(plan?.outline || (selectedMemory.length ? '承接当前情境，优先保持已发生事件、人物关系与原话事实一致。' : '自然承接当前对话，不强行引入无关记忆。'));
      shieldInfo = shieldHistoryMessages(config, getKeepRecentFloors(config));
      try {
        shieldInfo = await applySoftHistoryTrim(config, shieldInfo);
      } catch (error) {
        degraded = [degraded, `历史裁剪失败：${error.message || error}`].filter(Boolean).join(' · ');
      }
      const content = buildUnifiedPrompt(config, evidence, selectedEntries, outline, detailLevel, recapText, characterText, shieldInfo);
      applyInjection(config, content);
      lastUserMessageId = latestUser.id;
      recordInjectionResult({
        config,
        selectedEntries,
        content,
        reason: `${plan?.reason || (degraded ? '本地召回降级' : '本地融合')} · 记忆 ${evidence.length} 条 · ${detailLevel} · ${rerankMode} · 保留近 ${shieldInfo.kept} 楼原文 · 裁剪旧史 ${shieldInfo.shielded} 楼${shieldInfo.keepRange ? `（保留 ${shieldInfo.keepRange}）` : ''}${degraded ? ` · ${degraded}` : ''}`,
      });
      const last = loadLastInjection() || {};
      saveLastInjection({
        ...last,
        memory: evidence,
        memoryCandidates: selectedMemory,
        outline,
        recap: recapText,
        characters: characterText,
        storyState,
        detailLevel,
        elapsedMs: Math.round(performance.now() - startedAt),
        degraded,
        rerankMode,
        embeddingEnabled: !!config.embeddingEnabled,
        shielded: shieldInfo.shielded,
        keptRecent: shieldInfo.kept,
        keepRange: shieldInfo.keepRange || '',
        shieldMode: shieldInfo.mode || 'prompt_trim',
        trimApplied: !!shieldInfo.applied,
      });
      if (config.showDanmaku !== false) showInjectionDanmaku(selectedEntries);
      if (showResult) notify(`召回完成：记忆 ${evidence.length} 条，保留近 ${shieldInfo.kept} 楼，裁剪 ${shieldInfo.shielded} 楼`, 'success');
    } catch (error) {
      applyInjection(config, '');
      await unshieldHistoryMessages();
      recordInjectionResult({ config, selectedEntries: [], content: '', reason: '增强失败，已放行正常生成', error: error.message || String(error) });
      if (showResult) notify(`叙忆中枢降级：${error.message || error}`, 'warning');
    } finally {
      running = false;
    }
  }

  async function fetchModels(config) {
    const baseUrl = normalizeBaseUrl(config.baseUrl);
    if (!baseUrl) throw new Error('请先填写 API 地址');
    let response;
    try {
      response = await fetch(`${baseUrl}/models`, {
        headers: config.apiKey ? { Authorization: `Bearer ${config.apiKey}` } : {},
      });
    } catch (error) {
      throw new Error(`无法连接 ${baseUrl}/models：${error.message || error}`);
    }
    let data;
    try {
      data = await response.json();
    } catch (error) {
      throw new Error(`模型接口返回非 JSON：${response.status}`);
    }
    if (!response.ok) throw new Error(data?.error?.message || `模型读取失败：${response.status}`);
    const models = Array.isArray(data?.data)
      ? data.data.map((item) => String(item.id || item.name || '')).filter(Boolean)
      : Array.isArray(data) ? data.map((item) => String(item.id || item.name || item)).filter(Boolean) : [];
    const unique = [...new Set(models)].sort((a, b) => a.localeCompare(b));
    if (!unique.length) throw new Error('未获取到模型列表');
    return unique;
  }

  function buildModelOptions(models, current) {
    const list = [...new Set([...(models || []), current].filter(Boolean))];
    if (!list.length) return '<option value="">请先读取模型列表</option>';
    return list.map((model) => `<option value="${escapeHtml(model)}" ${model === current ? 'selected' : ''}>${escapeHtml(model)}</option>`).join('');
  }

  function fillModelSelect($select, models, current) {
    $select.html(buildModelOptions(models, current));
    const list = [...new Set([...(models || []), current].filter(Boolean))];
    $select.val(current && list.includes(current) ? current : (list[0] || ''));
  }

  function hydrateApiFromGlobalBackup(config) {
    if (config.baseUrl || config.apiKey || config.model) return config;
    try {
      const globalVars = safeGetVars(GLOBAL_OPTION);
      const api = globalVars.worldbook_smart_retriever_api;
      if (!api || typeof api !== 'object') return config;
      return normalizeConfig({ ...config, ...pickApiSettings(api) });
    } catch (error) {
      return config;
    }
  }

